@Service
public class MfaService {
    private static final int BACKUP_CODES_COUNT = 10;
    private static final int CODE_LENGTH = 8;
    
    @Autowired
    private UserMfaInfoRepository userMfaInfoRepository;
    
    @Autowired
    private BCryptPasswordEncoder bCryptPasswordEncoder;
    
    public void generateBackupCodes(String username) {
        UserMfaInfo userMfaInfo = userMfaInfoRepository.findByUsername(username);
        if (userMfaInfo == null) {
            throw new RuntimeException("User not found");
        }
        
        List<String> backupCodes = generateUniqueBackupCodes();
        String encryptedCodes = encryptBackupCodes(backupCodes);
        
        userMfaInfo.setBackupCodes(encryptedCodes);
        userMfaInfo.setMfaEnabled(true);
        userMfaInfoRepository.save(userMfaInfo);
    }
    
    public boolean validateBackupCode(String username, String backupCode) {
        UserMfaInfo userMfaInfo = userMfaInfoRepository.findByUsername(username);
        if (userMfaInfo == null || !userMfaInfo.isMfaEnabled() || userMfaInfo.getBackupCodes() == null) {
            return false;
        }
        
        List<String> codes = decryptBackupCodes(userMfaInfo.getBackupCodes());
        if (codes == null || codes.isEmpty()) {
            return false;
        }
        
        for (int i = 0; i < codes.size(); i++) {
            if (bCryptPasswordEncoder.matches(backupCode, codes.get(i))) {
                codes.remove(i);
                userMfaInfo.setBackupCodes(encryptBackupCodes(codes));
                userMfaInfoRepository.save(userMfaInfo);
                return true;
            }
        }
        
        return false;
    }
    
    private List<String> generateUniqueBackupCodes() {
        List<String> codes = new ArrayList<>();
        SecureRandom random = new SecureRandom();
        StringBuilder codeBuilder = new StringBuilder();
        
        for (int i = 0; i < BACKUP_CODES_COUNT; i++) {
            codeBuilder.setLength(0);
            for (int j = 0; j < CODE_LENGTH; j++) {
                codeBuilder.append(random.nextInt(10));
            }
            codes.add(bCryptPasswordEncoder.encode(codeBuilder.toString()));
        }
        
        return codes;
    }
    
    private String encryptBackupCodes(List<String> codes) {
        StringBuilder encrypted = new StringBuilder();
        for (String code : codes) {
            encrypted.append(code).append("|");
        }
        return encrypted.toString();
    }
    
    private List<String> decryptBackupCodes(String encryptedCodes) {
        if (encryptedCodes == null || encryptedCodes.isEmpty()) {
            return new ArrayList<>();
        }
        String[] codes = encryptedCodes.split("\\|");
        List<String> result = new ArrayList<>();
        for (String code : codes) {
            if (!code.isEmpty()) {
                result.add(code);
            }
        }
        return result;
    }
}

@RestController
@RequestMapping("/api/mfa")
public class MfaController {
    @Autowired
    private MfaService mfaService;
    
    @PostMapping("/enable")
    public ResponseEntity<?> enableMfa(@RequestBody EnableMfaRequest request) {
        try {
            mfaService.generateBackupCodes(request.getUsername());
            return ResponseEntity.ok().build();
        } catch (Exception e) {
            return ResponseEntity.status(500).body("Failed to enable MFA");
        }
    }
    
    @PostMapping("/authenticate")
    public ResponseEntity<?> authenticateWithBackupCode(@RequestBody BackupCodeRequest request) {
        boolean isValid = mfaService.validateBackupCode(request.getUsername(), request.getBackupCode());
        if (isValid) {
            return ResponseEntity.ok().build();
        } else {
            return ResponseEntity.status(401).body("Invalid backup code");
        }
    }
}

